import java.util.*;
import java.util.concurrent.*;
import java.util.function.Supplier;

public class RetryWithBackoff {

    // ── Retry with exponential backoff + jitter ───────────────────
    static <T> T retryWithBackoff(
            Supplier<T> action,
            int maxAttempts,
            long baseDelayMs,
            long maxDelayMs) throws Exception {

        Random rng = new Random();
        Exception lastException = null;

        for (int attempt = 1; attempt <= maxAttempts; attempt++) {
            try {
                return action.get(); // attempt the operation
            } catch (Exception e) {
                lastException = e;
                if (attempt == maxAttempts) break; // don't sleep on last attempt

                // Exponential backoff: base * 2^(attempt-1)
                long delay = Math.min(baseDelayMs * (1L << (attempt - 1)), maxDelayMs);
                // Full jitter: randomize between 0 and delay (spreads retries)
                long jitter = (long)(rng.nextDouble() * delay);

                System.out.printf("Attempt %d failed: %s. Retrying in %dms...%n",
                    attempt, e.getMessage(), jitter);
                Thread.sleep(jitter);
            }
        }
        throw new RuntimeException("All " + maxAttempts + " attempts failed", lastException);
    }

    // ── Timeout wrapper ───────────────────────────────────────────
    static <T> T withTimeout(Supplier<T> action, long timeoutMs) throws Exception {
        ExecutorService exec = Executors.newSingleThreadExecutor();
        Future<T> future = exec.submit(action::get);
        try {
            return future.get(timeoutMs, TimeUnit.MILLISECONDS);
        } catch (TimeoutException e) {
            future.cancel(true);
            throw new RuntimeException("Operation timed out after " + timeoutMs + "ms");
        } finally {
            exec.shutdownNow();
        }
    }

    // ── Demo: simulated flaky service ─────────────────────────────
    static int callCount = 0;
    static String flakyService() {
        callCount++;
        if (callCount < 3) throw new RuntimeException("Service temporarily unavailable");
        return "Success on attempt " + callCount;
    }

    public static void main(String[] args) throws Exception {
        callCount = 0;
        String result = retryWithBackoff(
            RetryWithBackoff::flakyService,
            5,          // max attempts
            100,        // base delay ms
            5000        // max delay ms
        );
        System.out.println("Result: " + result);

        // Timeout demo
        try {
            withTimeout(() -> {
                try { Thread.sleep(2000); } catch (InterruptedException e) {}
                return "too late";
            }, 500);
        } catch (RuntimeException e) {
            System.out.println(e.getMessage());
        }
    }
}

import java.util.*;
import java.util.concurrent.ConcurrentHashMap;

/**
 * Idempotency Pattern
 * Problem: client sends POST /payments, times out, retries → double charge
 * Solution: client sends Idempotency-Key: UUID, server deduplicates
 */
public class IdempotencyPattern {

    record PaymentRequest(String idempotencyKey, long userId, double amount) {}
    record PaymentResult(String status, String transactionId, boolean wasDuplicate) {}

    // ── In-memory store (production: Redis or DB table) ───────────
    static Map<String, PaymentResult> processedRequests = new ConcurrentHashMap<>();

    static PaymentResult processPayment(PaymentRequest req) {
        // Check idempotency: was this key already processed?
        PaymentResult cached = processedRequests.get(req.idempotencyKey());
        if (cached != null) {
            System.out.println("Duplicate request detected, returning cached result");
            return new PaymentResult(cached.status(), cached.transactionId(), true);
        }

        // Process payment (would call payment gateway)
        String txId = "TXN-" + UUID.randomUUID().toString().substring(0, 8);
        PaymentResult result = new PaymentResult("SUCCESS", txId, false);

        // Store result ATOMICALLY with processing (in DB: same transaction)
        // If we store after processing and the server crashes, we lose idempotency
        processedRequests.put(req.idempotencyKey(), result);

        System.out.println("Processed payment: " + txId + " for user " + req.userId());
        return result;
    }

    // ── Database-backed idempotency (production pattern) ─────────
    /*
    -- Schema:
    CREATE TABLE idempotency_requests (
        idempotency_key VARCHAR(64) PRIMARY KEY,
        response_body   TEXT,
        created_at      DATETIME DEFAULT NOW(),
        expires_at      DATETIME  -- TTL: e.g., NOW() + INTERVAL 24 HOUR
    );

    -- In service method (Spring):
    @Transactional
    public PaymentResult processPayment(String idempotencyKey, PaymentRequest req) {
        // 1. Try to INSERT idempotency key (will fail on duplicate PK)
        try {
            idempotencyRepo.insert(idempotencyKey, null, expiresAt);
        } catch (DuplicateKeyException e) {
            return idempotencyRepo.getResponse(idempotencyKey); // return cached
        }
        // 2. Process (same transaction)
        PaymentResult result = paymentGateway.charge(req);
        // 3. Store result
        idempotencyRepo.update(idempotencyKey, serialize(result));
        return result;
    }
    */

    public static void main(String[] args) {
        String key = UUID.randomUUID().toString();
        PaymentRequest req = new PaymentRequest(key, 42L, 99.99);

        // First request: processed normally
        PaymentResult r1 = processPayment(req);
        System.out.println("First:  " + r1);

        // Retry (network timeout simulation): same idempotency key
        PaymentResult r2 = processPayment(req);
        System.out.println("Retry:  " + r2);

        // Same transaction ID, no double charge
        System.out.println("Same TXN? " + r1.transactionId().equals(r2.transactionId()));
        System.out.println("Was duplicate? " + r2.wasDuplicate());
    }
}

