public class Q1 {
    static void retry(Runnable action, int maxAttempts, long baseDelayMs) {
        RuntimeException last = null;
        for (int attempt = 1; attempt <= maxAttempts; attempt++) {
            try {
                action.run();
                return; // success
            } catch (RuntimeException e) {
                last = e;
                if (attempt < maxAttempts) {
                    long delay = baseDelayMs * (1L << (attempt - 1)); // 10, 20, 40...
                    try { Thread.sleep(delay); } catch (InterruptedException ie) { Thread.currentThread().interrupt(); }
                }
            }
        }
        throw new RuntimeException("All " + maxAttempts + " attempts failed", last);
    }

    public static void main(String[] args) {
        int[] attempts = {0};
        try {
            retry(() -> {
                attempts[0]++;
                if (attempts[0] < 3) throw new RuntimeException("fail " + attempts[0]);
                System.out.println("Succeeded on attempt " + attempts[0]);
            }, 5, 10);
        } catch (RuntimeException e) {
            System.out.println("All attempts failed: " + e.getMessage());
        }
    }
}

