import java.util.*;

public class Q2 {
    static Map<String, Integer> counters = new HashMap<>();
    static Set<String> processedIds = new HashSet<>();

    static int increment(String requestId, String counterId) {
        if (!processedIds.contains(requestId)) {
            counters.merge(counterId, 1, Integer::sum);
            processedIds.add(requestId);
        }
        return counters.getOrDefault(counterId, 0);
    }

    public static void main(String[] args) {
        System.out.println(increment("req-1", "views"));  // 1
        System.out.println(increment("req-2", "views"));  // 2
        System.out.println(increment("req-1", "views"));  // 2 (duplicate, returns current)
        System.out.println(increment("req-3", "views"));  // 3
        System.out.println("Final: " + counters.get("views")); // 3
    }
}

