import java.util.concurrent.*;
import java.util.function.Supplier;

public class Q3 {
    static class BulkheadFullException extends RuntimeException {
        BulkheadFullException(int max) { super("Bulkhead full: max " + max + " concurrent calls"); }
    }

    static class Bulkhead {
        private final int maxConcurrent;
        private final Semaphore semaphore;

        Bulkhead(int maxConcurrent) {
            this.maxConcurrent = maxConcurrent;
            this.semaphore = new Semaphore(maxConcurrent);
        }

        <T> T execute(Supplier<T> action) {
            if (!semaphore.tryAcquire()) { // fail fast — no waiting
                throw new BulkheadFullException(maxConcurrent);
            }
            try {
                return action.get();
            } finally {
                semaphore.release(); // always release
            }
        }
    }

    public static void main(String[] args) throws Exception {
        Bulkhead bh = new Bulkhead(2);
        ExecutorService exec = Executors.newFixedThreadPool(4);

        for (int i = 0; i < 4; i++) {
            final int id = i;
            exec.submit(() -> {
                try {
                    bh.execute(() -> {
                        try { Thread.sleep(200); } catch (InterruptedException e) {}
                        return "done-" + id;
                    });
                    System.out.println("Task " + id + " succeeded");
                } catch (BulkheadFullException e) {
                    System.out.println("Task " + id + " rejected: " + e.getMessage());
                }
            });
        }
        exec.shutdown();
        exec.awaitTermination(2, TimeUnit.SECONDS);
    }
}
